"use client";
import React from "react";
import Box, { BoxProps } from "@mui/material/Box";
import Typography from "@mui/material/Typography";

const Menu = ({
  active,
  children,
  ...props
}: { active?: boolean } & BoxProps) => (
  <Box
    display={"inline-flex"}
    alignItems={"center"}
    alignSelf={"stretch"}
    position={"relative"}
    px={2}
    color={active ? "secondary.main" : "common.white"}
    fontSize={18}
    {...props}
  >
    {children}
    {active && (
      <Box
        position={"absolute"}
        bottom={0}
        left={0}
        width={"100%"}
        bgcolor={"secondary.main"}
        height={4}
      />
    )}
  </Box>
);

const ReactHeader = ({ concise }: { concise?: boolean }) => (
  <>
    <Box
      display={"flex"}
      alignItems={"center"}
      mr={2}
      sx={{ flexShrink: 0, flexBasis: "calc(100% / 6)" }}
    >
      <img
        src={
          "data:image/svg+xml;base64,"
        }
        alt={"react logo"}
        style={{ height: 20 }}
      />
      <Typography color={"secondary"} variant={"h6"} style={{ marginLeft: 8 }}>
        <b>React</b>
      </Typography>
    </Box>
    <Box
      component={"nav"}
      display={"flex"}
      alignItems={"center"}
      alignSelf={"stretch"}
      overflow={"auto"}
    >
      <Menu active>Docs</Menu>
      <Menu>Tutorial</Menu>
      <Menu>Blog</Menu>
      <Menu>Community</Menu>
    </Box>
    {!concise && (
      <Box ml={"auto"}>
        <Menu fontSize={16}>v16.12.0</Menu>
        <Menu fontSize={16}>Languages</Menu>
        <Menu fontSize={16}>Github</Menu>
      </Box>
    )}
  </>
);

export default ReactHeader;

"use client";
import React from "react";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import Link from "@mui/material/Link";
import Typography from "@mui/material/Typography";

const ReactNextArticle = () => (
  <Box bgcolor={"rgb(40, 44, 52)"}>
    <Container disableGutters>
      <Box
        mr={{ xs: 0, md: 10 }}
        py={5}
        px={{ xs: 2, sm: 3, md: 0 }}
        textAlign={"right"}
        color={"common.white"}
      >
        <Typography color={"secondary"} variant={"subtitle2"}>
          Next article
        </Typography>
        <Link
          href={"https://reactjs.org/docs/add-react-to-a-website.html"}
          target={"_blank"}
          rel={"noopener"}
          color={"inherit"}
          style={{ fontSize: 30 }}
        >
          Add React to a Website
        </Link>
      </Box>
    </Container>
  </Box>
);

export default ReactNextArticle;

export { default as ReactHeader } from "./ReactHeader";
export { default as ReactNextArticle } from "./ReactNextArticle";
export { default as ReactContent } from "./ReactContent";
